284	// TestACCheck_RegressionFakeRetainDays replays the shape of the fake
285	// commits b7c18c7a1 / d73eaffc6 / 34b412254 (each claimed "implement
286	// pruneAgentLogs / pruneWorkerDirs / counters / 5 tests" but only changed
287	// a default value). The ac-check tool MUST report failure for the AC items
288	// that named missing symbols and tests.
289	func TestACCheck_RegressionFakeRetainDays(t *testing.T) {
290		// Mimic the bead's acceptance text (abbreviated).
291		acceptance := `1. cli/internal/agent/execution_cleanup.go has a ` + "`pruneOlderThan`" + ` helper.
292	2. ` + "`RemovedExecutionDirs`" + `, ` + "`RemovedAgentLogs`" + `, ` + "`RemovedWorkerDirs`" + ` counters are added.
293	3. Default RetainDays is 90 (not 7).
294	4. TestExecutionCleanup_DeletesOldAgentLogs passes.
295	5. lefthook run pre-commit passes.`
296		items := ParseAcceptance(acceptance)
297		if len(items) != 5 {
298			t.Fatalf("expected 5 items, got %d", len(items))
299		}
300	
301		// Simulate the fake-work diff: only types.go default value changed.
302		// No pruneOlderThan in the tree. No counters added. No test added.
303		ctx := Context{
304			RunTest: func(name string, _ []string) (bool, string, error) {
305				// No matching test exists in the fake diff.
