93	// LoadWithWorkingDir loads configuration from a specific working directory
94	func LoadWithWorkingDir(workingDir string) (*Config, error) {
95		if workingDir == "" {
96			var err error
97			workingDir, err = os.Getwd()
98			if err != nil {
99				return nil, fmt.Errorf("failed to get working directory: %w", err)
100			}
101		}
102	
103		// Use the new ConfigLoader to load from .ddx/config.yaml only
104		loader, err := NewConfigLoaderWithWorkingDir(workingDir)
105		if err != nil {
106			return nil, fmt.Errorf("failed to create config loader: %w", err)
107		}
108	
109		// Pre-validation migration check: surface a friendly hard error for
110		// removed agent.routing fields before the schema validator sees the file.
111		// This happens before LoadConfig so the migration message is what the
112		// operator sees.
113		configPath := filepath.Join(workingDir, ".ddx", "config.yaml")
114		if data, readErr := os.ReadFile(configPath); readErr == nil {
115			if migErr := checkRoutingMigration(configPath, data); migErr != nil {
116				return nil, migErr
117			}
118		}
119	
120		config, err := loader.LoadConfig()
121		if err != nil {
122			// If no config file exists, return default config
123			if os.IsNotExist(err) || strings.Contains(err.Error(), "no configuration file found") {
124				config = DefaultNewConfig()
125			} else {
126				return nil, err
127			}
128		}
129	
130		// Apply defaults to ensure complete configuration
131		config.ApplyDefaults()
132		if config.Agent != nil && config.Agent.Routing != nil &&
133			len(config.Agent.Routing.ProfilePriority) > 0 {
134			fmt.Fprintln(os.Stderr, "warning: agent.routing.profile_priority is deprecated and will be removed in a future version")
135		}
136	
137		// Override library path with environment variable if set
138		if envLibraryPath := os.Getenv("DDX_LIBRARY_BASE_PATH"); envLibraryPath != "" {
139			config.Library.Path = envLibraryPath
140		}
141	
142		// Validate the final configuration
143		if err := config.Validate(); err != nil {
144			return nil, fmt.Errorf("configuration validation failed: %w", err)
145		}
146	
147		return config, nil
148	}
