126	func (f *CommandFactory) resolveCommitSHA(commitSHA string) (string, error) {
127		if commitSHA == "" {
128			return "", nil
129		}
130	
131		ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
132		defer cancel()
133	
134		repoDir := f.WorkingDir
135		if repoDir == "" {
136			repoDir = "."
137		}
138	
139		if isFullCommitSHA(commitSHA) && !gitpkg.IsRepository(repoDir) {
140			return commitSHA, nil
141		}
142	
143		cmd := gitpkg.Command(ctx, repoDir, "rev-parse", "--verify", commitSHA+"^{commit}")
144		out, err := cmd.Output()
145		if err != nil {
146			return "", fmt.Errorf("git rev-parse %s: %w", commitSHA, err)
147		}
148		return strings.TrimSpace(string(out)), nil
149	}
150	
151	func isFullCommitSHA(commitSHA string) bool {
152		if len(commitSHA) != 40 {
153			return false
154		}
155		for i := 0; i < len(commitSHA); i++ {
156			c := commitSHA[i]
157			if c >= '0' && c <= '9' {
158				continue
159			}
160			if c >= 'a' && c <= 'f' {
161				continue
162			}
163			if c >= 'A' && c <= 'F' {
164				continue
165			}
166			return false
167		}
168		return true
169	}
170	
171	func (f *CommandFactory) resolveClosingCommitSHA(commitSHA string) (string, error) {
172		normalizedCommitSHA, err := f.resolveCommitSHA(commitSHA)
173		if err != nil {
174			return "", fmt.Errorf("invalid closing_commit_sha %q: %w", commitSHA, err)
175		}
176		if normalizedCommitSHA == "" {
177			return "", fmt.Errorf("invalid closing_commit_sha %q: empty value", commitSHA)
178		}
