229				if !filepath.IsAbs(dir) && f.WorkingDir != "" {
230					if workspaceRoot := gitpkg.FindNearestDDxWorkspace(f.WorkingDir); workspaceRoot != "" {
231						return workspaceRoot
232					}
233					dir = filepath.Join(f.WorkingDir, dir)
234				}
235				return filepath.Dir(dir)
236			}
237			if !filepath.IsAbs(dir) && f.WorkingDir != "" {
238				return filepath.Join(f.WorkingDir, dir)
239			}
240			return dir
241		}
242		if f.WorkingDir == "" {
243			return ""
244		}
245		if workspaceRoot := gitpkg.FindNearestDDxWorkspace(f.WorkingDir); workspaceRoot != "" {
246			return workspaceRoot
247		}
248		return f.WorkingDir
