490			RunE: func(cmd *cobra.Command, args []string) error {
491				if err := f.checkLifecycleMigrationGate(cmd); err != nil {
492					return err
493				}
494				s := f.beadStore()
495	
496				// --claim and --unclaim use dedicated store methods
497				if claim, _ := cmd.Flags().GetBool("claim"); claim {
498					assignee, _ := cmd.Flags().GetString("assignee")
499					if assignee == "" {
500						assignee = resolveClaimAssignee()
501					}
502					if err := s.Claim(args[0], assignee); err != nil {
503						return err
504					}
505					if _, err := f.beadAutoCommit("claim " + args[0]); err != nil {
506						return err
507					}
508					return nil
509				}
510				if unclaim, _ := cmd.Flags().GetBool("unclaim"); unclaim {
511					if err := s.Unclaim(args[0]); err != nil {
512						return err
513					}
514					if _, err := f.beadAutoCommit("unclaim " + args[0]); err != nil {
515						return err
516					}
517					return nil
518				}
519	
520				if unsetFlags, _ := cmd.Flags().GetStringArray("unset"); len(unsetFlags) > 0 {
521					for _, key := range unsetFlags {
522						if isProtectedBeadExtraKey(key) {
523							return fmt.Errorf("cannot unset protected bead field: %s", key)
524						}
525					}
526				}
527	
528				var setFlags []string
529				if rawSetFlags, _ := cmd.Flags().GetStringArray("set"); len(rawSetFlags) > 0 {
530					setFlags = make([]string, 0, len(rawSetFlags))
531					for _, kv := range rawSetFlags {
532						k, v, ok := strings.Cut(kv, "=")
533						if !ok {
534							return fmt.Errorf("--set requires key=value format, got: %s", kv)
535						}
536						if k == "closing_commit_sha" {
537							normalizedCommitSHA, err := f.resolveClosingCommitSHA(v)
538							if err != nil {
539								return err
540							}
541							v = normalizedCommitSHA
542						}
543						setFlags = append(setFlags, k+"="+v)
544					}
545				}
546	
547				statusValue, _ := cmd.Flags().GetString("status")
548				statusChanged := cmd.Flags().Changed("status")
549				statusOpts := beadTransitionOptionsFromSetFlags(statusValue, setFlags, "ddx bead update")
550	
551				applyUpdateFields := func(b *bead.Bead) error {
552					if v, _ := cmd.Flags().GetString("title"); cmd.Flags().Changed("title") {
553						b.Title = v
554					}
555					if v, _ := cmd.Flags().GetInt("priority"); cmd.Flags().Changed("priority") {
556						b.Priority = v
557					}
558					if v, _ := cmd.Flags().GetString("labels"); cmd.Flags().Changed("labels") {
559						if v == "" {
560							b.Labels = []string{}
561						} else {
562							b.Labels = strings.Split(v, ",")
563						}
564					}
565					if v, _ := cmd.Flags().GetString("acceptance"); cmd.Flags().Changed("acceptance") {
566						b.Acceptance = v
567					}
568					if v, _ := cmd.Flags().GetString("assignee"); cmd.Flags().Changed("assignee") {
569						b.Owner = v
570					}
571					if v, _ := cmd.Flags().GetString("parent"); cmd.Flags().Changed("parent") {
572						b.Parent = v
573					}
574					if v, _ := cmd.Flags().GetString("description"); cmd.Flags().Changed("description") {
575						b.Description = v
576					}
577					if v, _ := cmd.Flags().GetString("notes"); cmd.Flags().Changed("notes") {
578						b.Notes = v
579					}
580					if len(setFlags) > 0 {
581						if b.Extra == nil {
582							b.Extra = make(map[string]any)
583						}
584						for _, kv := range setFlags {
585							k, v, ok := strings.Cut(kv, "=")
586							if !ok {
587								continue
588							}
589							// Route known field names to struct fields
590							switch k {
591							case "parent":
592								b.Parent = v
593							case "description":
594								b.Description = v
595							case "notes":
596								b.Notes = v
597							case "acceptance":
598								b.Acceptance = v
599							case "issue_type":
600								b.IssueType = v
601							default:
602								// Parse booleans and numbers for proper typing
603								switch v {
604								case "true":
605									b.Extra[k] = true
606								case "false":
607									b.Extra[k] = false
608								default:
609									b.Extra[k] = v
610								}
611							}
612						}
613					}
614					if unsetFlags, _ := cmd.Flags().GetStringArray("unset"); len(unsetFlags) > 0 {
615						for _, key := range unsetFlags {
616							if b.Extra != nil {
617								delete(b.Extra, key)
618							}
619						}
620					}
621					return nil
622				}
623	
624				var err error
625				if statusChanged {
626					err = s.UpdateWithLifecycleStatus(args[0], statusValue, statusOpts, applyUpdateFields)
627				} else {
628					err = s.Update(args[0], func(b *bead.Bead) {
629						_ = applyUpdateFields(b)
630					})
631				}
632				if err != nil {
633					return err
634				}
635				if _, err := f.beadAutoCommit("update " + args[0]); err != nil {
636					return err
637				}
638				return nil
639			},
640		}
641	
642		cmd.Flags().String("title", "", "New title")
643		cmd.Flags().String("status", "", "New lifecycle status (validated transition)")
644		cmd.Flags().Int("priority", 0, "New priority")
645		cmd.Flags().String("labels", "", "New labels (comma-separated)")
646		cmd.Flags().String("acceptance", "", "New acceptance criteria")
647		cmd.Flags().String("assignee", "", "New assignee or claim assignee fallback")
648		cmd.Flags().String("parent", "", "New parent bead ID")
649		cmd.Flags().String("description", "", "New description")
650		cmd.Flags().String("notes", "", "New notes")
