1229	func normalizeChildIDs(children []string) []string {
1230		var out []string
1231		seen := map[string]bool{}
1232		for _, raw := range children {
1233			for _, part := range strings.Split(raw, ",") {
1234				child := strings.TrimSpace(part)
1235				if child == "" || seen[child] {
1236					continue
1237				}
1238				seen[child] = true
1239				out = append(out, child)
1240			}
1241		}
1242		return out
1243	}
