1068	// Events returns the bead's evidence history in insertion order. Reads are
1069	// transparent across storage shapes: inline Extra["events"] for active beads,
1070	// or the externalized sidecar referenced by Extra[events_attachment] once the
1071	// bead has been closed.
1072	func (s *Store) Events(id string) ([]BeadEvent, error) {
1073		b, err := s.Get(id)
1074		if err != nil {
1075			return nil, err
1076		}
1077		events, err := s.eventsForBead(b)
1078		if err != nil {
1079			return nil, err
1080		}
1081		if len(events) == 0 {
1082			return []BeadEvent{}, nil
1083		}
1084		out := make([]BeadEvent, len(events))
1085		copy(out, events)
1086		return out, nil
1087	}
