66	// LoadConfig loads configuration from .ddx/config.yaml only
67	func (cl *ConfigLoader) LoadConfig() (*NewConfig, error) {
68		// Only support new format: .ddx/config.yaml
69		configPath := filepath.Join(cl.workingDir, ".ddx", "config.yaml")
70		if _, err := os.Stat(configPath); err != nil {
