77	// LoadConfigFromPath loads configuration from a specific path (new format only)
78	func (cl *ConfigLoader) LoadConfigFromPath(path string) (*NewConfig, error) {
79		// Convert relative path to absolute based on working directory
80		if !filepath.IsAbs(path) {
81			path = filepath.Join(cl.workingDir, path)
82		}
83	
84		return cl.loadNewFormat(path)
85	}
86	
87	// loadNewFormat loads and validates the new configuration format
88	func (cl *ConfigLoader) loadNewFormat(path string) (*NewConfig, error) {
89		// Read file
90		data, err := os.ReadFile(path)
91		if err != nil {
92			return nil, fmt.Errorf("failed to read config file %s: %w", path, err)
93		}
94	
95		// Validate using two-phase validation
96		if err := cl.validator.Validate(data); err != nil {
97			return nil, fmt.Errorf("configuration validation failed: %w", err)
98		}
99	
100		// Parse YAML into new config structure
101		var config NewConfig
102		if err := yaml.Unmarshal(data, &config); err != nil {
103			return nil, fmt.Errorf("failed to parse config YAML from %s: %w", path, err)
104		}
105	
106		// Apply defaults to missing fields
107		config.ApplyDefaults()
108	
109		return &config, nil
110	}
111	
112	// SaveConfig saves configuration in the new format
113	func (cl *ConfigLoader) SaveConfig(config *NewConfig, path string) error {
114		// Convert relative path to absolute based on working directory
115		if !filepath.IsAbs(path) {
116			path = filepath.Join(cl.workingDir, path)
117		}
118	
119		// Create directory if it doesn't exist
120		dir := filepath.Dir(path)
121		if err := os.MkdirAll(dir, 0755); err != nil {
122			return fmt.Errorf("failed to create config directory %s: %w", dir, err)
123		}
124	
125		// Marshal to YAML
126		data, err := yaml.Marshal(config)
127		if err != nil {
128			return fmt.Errorf("failed to marshal config: %w", err)
129		}
130	
131		// Validate before saving
132		if err := cl.validator.Validate(data); err != nil {
133			return fmt.Errorf("config validation failed before save: %w", err)
134		}
135	
136		// Write file with secure permissions
137		if err := os.WriteFile(path, data, 0644); err != nil {
138			return fmt.Errorf("failed to write config file %s: %w", path, err)
139		}
140	
141		return nil
142	}
143	
144	// DetectConfigFormat determines if .ddx/config.yaml exists in working directory
145	func (cl *ConfigLoader) DetectConfigFormat() (string, string, error) {
146		configPath := filepath.Join(cl.workingDir, ".ddx", "config.yaml")
147		if _, err := os.Stat(configPath); err == nil {
148			return "new", configPath, nil
149		}
150	
151		return "none", "", fmt.Errorf("no configuration file found at %s", configPath)
152	}
