151	func isFullCommitSHA(commitSHA string) bool {
152		if len(commitSHA) != 40 {
153			return false
154		}
155		for i := 0; i < len(commitSHA); i++ {
156			c := commitSHA[i]
157			if c >= '0' && c <= '9' {
158				continue
159			}
160			if c >= 'a' && c <= 'f' {
161				continue
162			}
163			if c >= 'A' && c <= 'F' {
164				continue
165			}
166			return false
167		}
168		return true
169	}
