171	func (f *CommandFactory) resolveClosingCommitSHA(commitSHA string) (string, error) {
172		normalizedCommitSHA, err := f.resolveCommitSHA(commitSHA)
173		if err != nil {
174			return "", fmt.Errorf("invalid closing_commit_sha %q: %w", commitSHA, err)
175		}
176		if normalizedCommitSHA == "" {
177			return "", fmt.Errorf("invalid closing_commit_sha %q: empty value", commitSHA)
178		}
179		return normalizedCommitSHA, nil
180	}
