668	func isProtectedBeadExtraKey(key string) bool {
669		switch key {
670		case "events", "session_id", "claimed-at", "claimed-pid", "claimed-machine", "claimed-session", "claimed-worktree":
671			return true
672		default:
673			return false
674		}
675	}
