677	// beadHasLegacyLifecycleInputs detects beads that require lifecycle migration
678	// before they can be executed. Migration-only: these status values and labels
679	// are legacy; new rows use canonical statuses and the lifecycle state machine.
680	func beadHasLegacyLifecycleInputs(b bead.Bead) bool {
681		if b.Status == "needs_investigation" || b.Status == "needs_human" {
682			return true
683		}
684		for _, label := range b.Labels {
685			if label == bead.LabelNeedsHuman || label == bead.LabelNeedsInvestigation {
686				return true
687			}
688		}
689		return false
690	}
