1202	func removeBeadLabel(b *bead.Bead, label string) {
1203		if b == nil {
1204			return
1205		}
1206		labels := b.Labels[:0]
1207		for _, existing := range b.Labels {
1208			if existing != label {
1209				labels = append(labels, existing)
1210			}
1211		}
1212		b.Labels = labels
1213	}
