1215	func appendNeedsHumanResolutionEvent(s *bead.Store, id, action, note string, children []string) error {
1216		body := note
1217		if len(children) > 0 {
1218			body = fmt.Sprintf("%s\nchildren: %s", note, strings.Join(children, ", "))
1219		}
1220		return s.AppendEvent(id, bead.BeadEvent{
1221			Kind:    "needs_human_resolved",
1222			Summary: "action=" + action,
1223			Body:    body,
1224			Actor:   resolveClaimAssignee(),
1225			Source:  "ddx bead human resolve",
1226		})
1227	}
