1608	// newBeadCooldownCommand wires `ddx bead cooldown show|clear <id>`.
1609	//
1610	// `cooldown show` prints the bead's current work cooldown fields
1611	// (retry-after, last-status, last-detail) in human or JSON form. `cooldown
1612	// clear` removes those three fields so the bead becomes execution-eligible
1613	// again at the next loop pass. This is the first-class operator-facing
1614	// surface for the underlying `execute-loop-retry-after` Extra key — the
1615	// `ddx bead update --set/--unset execute-loop-retry-after=...` workflow
1616	// continues to work as a power-user fallback, but operators should reach
1617	// for `cooldown clear` for the common case.
1618	func (f *CommandFactory) newBeadCooldownCommand() *cobra.Command {
1619		cmd := &cobra.Command{
1620			Use:   "cooldown",
1621			Short: "Inspect and clear work cooldowns",
1622			Long: `Inspect and clear the work cooldown that parks a bead from
1623	re-execution. Cooldowns are set automatically by the loop in three cases:
1624	
1625	  * no_changes with a vague rationale (short retry, default 6h)
1626	  * push_failed (long park, 365d, requires operator action)
1627	  * declined_needs_decomposition (long park, 365d, requires decomposition)
1628	
1629	Use this command instead of editing the magic Extra key directly:
1630	
1631	  ddx bead cooldown show <bead-id>     # show retry-after, last-status, last-detail
1632	  ddx bead cooldown clear <bead-id>    # remove cooldown so the bead re-enters the queue
1633	`,
1634			Run: func(cmd *cobra.Command, args []string) { _ = cmd.Help() },
1635		}
1636	
1637		showCmd := &cobra.Command{
1638			Use:   "show <id>",
1639			Short: "Show the work cooldown fields for a bead",
1640			Args:  cobra.ExactArgs(1),
1641			RunE: func(cmd *cobra.Command, args []string) error {
1642				s := f.beadStore()
1643				b, err := s.Get(args[0])
1644				if err != nil {
1645					return err
1646				}
1647				retry, _ := b.Extra["execute-loop-retry-after"].(string)
1648				lastStatus, _ := b.Extra["execute-loop-last-status"].(string)
1649				lastDetail, _ := b.Extra["execute-loop-last-detail"].(string)
1650	
1651				asJSON, _ := cmd.Flags().GetBool("json")
1652				if asJSON {
1653					enc := json.NewEncoder(cmd.OutOrStdout())
1654					enc.SetIndent("", "  ")
1655					return enc.Encode(struct {
1656						BeadID      string `json:"bead_id"`
1657						RetryAfter  string `json:"retry_after,omitempty"`
1658						LastStatus  string `json:"last_status,omitempty"`
1659						LastDetail  string `json:"last_detail,omitempty"`
1660						ParkedUntil string `json:"parked_until,omitempty"`
1661					}{BeadID: b.ID, RetryAfter: retry, LastStatus: lastStatus, LastDetail: lastDetail, ParkedUntil: retry})
1662				}
1663	
1664				if retry == "" {
1665					fmt.Fprintf(cmd.OutOrStdout(), "%s: no cooldown set\n", b.ID)
1666					return nil
1667				}
1668				fmt.Fprintf(cmd.OutOrStdout(), "bead:        %s\n", b.ID)
1669				fmt.Fprintf(cmd.OutOrStdout(), "retry_after: %s\n", retry)
1670				if lastStatus != "" {
1671					fmt.Fprintf(cmd.OutOrStdout(), "last_status: %s\n", lastStatus)
1672				}
1673				if lastDetail != "" {
1674					fmt.Fprintf(cmd.OutOrStdout(), "last_detail: %s\n", lastDetail)
1675				}
1676				return nil
1677			},
1678		}
1679		showCmd.Flags().Bool("json", false, "Output as JSON")
1680		cmd.AddCommand(showCmd)
1681	
1682		clearCmd := &cobra.Command{
1683			Use:   "clear <id>",
1684			Short: "Clear the work cooldown for a bead",
1685			Args:  cobra.ExactArgs(1),
1686			RunE: func(cmd *cobra.Command, args []string) error {
1687				s := f.beadStore()
1688				cleared := false
1689				if err := s.Update(args[0], func(b *bead.Bead) {
1690					if b.Extra == nil {
1691						return
1692					}
1693					for _, key := range []string{
1694						"execute-loop-retry-after",
1695						"execute-loop-last-status",
1696						"execute-loop-last-detail",
1697					} {
1698						if _, ok := b.Extra[key]; ok {
1699							delete(b.Extra, key)
1700							cleared = true
1701						}
1702					}
1703				}); err != nil {
1704					return err
1705				}
1706				if _, err := f.beadAutoCommit("cooldown clear " + args[0]); err != nil {
1707					return err
1708				}
1709				if cleared {
1710					fmt.Fprintf(cmd.OutOrStdout(), "Cleared cooldown on %s\n", args[0])
1711				} else {
1712					fmt.Fprintf(cmd.OutOrStdout(), "%s: no cooldown set\n", args[0])
1713				}
1714				return nil
1715			},
1716		}
1717		cmd.AddCommand(clearCmd)
1718	
1719		return cmd
1720	}
