280	// decodePreClaimIntakePayloadResult decodes a JSON payload into a PreClaimIntakeResult.
281	// It accepts both the legacy intake schema (classification field) and the canonical
282	// readiness schema (outcome field), converting both into the same decision model.
283	func decodePreClaimIntakePayloadResult(payload string) (PreClaimIntakeResult, error) {
284		var probe struct {
285			Classification  string `json:"classification"`
286			Outcome         string `json:"outcome"`
287			Tractability    string `json:"tractability"`
288			Rationale       string `json:"rationale"`
289			Score           *int   `json:"score"`
290			ReadinessChecks []struct {
291				Reason string `json:"reason,omitempty"`
292			} `json:"readiness_checks"`
293			SuggestedFixes []struct {
294				Target string `json:"target,omitempty"`
295			} `json:"suggested_fixes"`
296		}
297		if err := json.Unmarshal([]byte(payload), &probe); err != nil {
298			return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: decode result: %w", err)
299		}
300		if probe.Outcome != "" {
301			return decodeCanonicalReadinessPayload(payload)
302		}
303		if probe.Classification != "" {
304			if isReadinessClassificationPayload(probe.Classification, probe.Tractability, probe.Rationale, probe.Score, len(probe.ReadinessChecks), len(probe.SuggestedFixes)) {
305				return decodeReadinessClassificationPayload(payload)
306			}
307			return decodeLegacyIntakePayload(payload)
308		}
309		return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: missing classification or outcome field")
310	}
311	
312	func isReadinessClassificationPayload(classification, tractability, rationale string, score *int, checkCount, fixCount int) bool {
313		switch strings.ToLower(strings.TrimSpace(classification)) {
314		case ReadinessClassificationSystemUnready,
315			"readiness_error",
316			"intake_error",
317			ReadinessClassificationNeedsRefine,
318			ReadinessClassificationNeedsSplit,
319			ReadinessClassificationOperatorRequired:
320			return true
321		case "ready":
322			return strings.TrimSpace(tractability) != "" ||
323				strings.TrimSpace(rationale) != "" ||
324				score != nil ||
325				checkCount > 0 ||
326				fixCount > 0
327		default:
328			return false
329		}
330	}
331	
332	func decodeCanonicalReadinessPayload(payload string) (PreClaimIntakeResult, error) {
333		var out preClaimReadinessPromptResult
334		if err := json.Unmarshal([]byte(payload), &out); err != nil {
335			return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: decode readiness result: %w", err)
336		}
337		detail := strings.TrimSpace(out.Reason)
338		if detail == "" {
339			detail = strings.TrimSpace(out.Detail)
340		}
341		rewrite := PreClaimIntakeRewrite{
342			Description:   strings.TrimSpace(out.Rewrite.Description),
343			Acceptance:    strings.TrimSpace(out.Rewrite.Acceptance),
344			ChangedFields: normalizePreClaimIntakeRewriteFields(out.Rewrite.ChangedFields),
345		}
346		switch strings.ToLower(strings.TrimSpace(out.Outcome)) {
347		case "actionable_atomic":
348			return PreClaimIntakeResult{Outcome: PreClaimIntakeActionableAtomic, Detail: detail}, nil
349		case "actionable_but_rewritten":
350			return PreClaimIntakeResult{Outcome: PreClaimIntakeActionableButRewritten, Detail: detail, Rewrite: rewrite}, nil
351		case "too_large_decomposed":
352			return PreClaimIntakeResult{Outcome: PreClaimIntakeTooLargeDecomposed, Reason: ReadinessReasonTooLarge, Detail: detail}, nil
353		case "operator_required", "human_review_required":
354			return PreClaimIntakeResult{Outcome: PreClaimIntakeOperatorRequired, Reason: ReadinessReasonAmbiguousScope, Detail: detail}, nil
355		case "ambiguous_needs_human", "needs_human":
356			return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: legacy readiness outcome %q removed by lifecycle migration; use %q", out.Outcome, PreClaimIntakeOperatorRequired)
357		case "readiness_error", "system_unready":
358			// system_unready maps to fail-open/skip per ADR-023/FEAT-010 policy
359			classified := ClassifyReadiness(ReadinessClassificationSystemUnready, nil, detail)
360			return PreClaimIntakeResult{
361				Outcome:      PreClaimIntakeError,
362				Reason:       classified.Reason,
363				SystemReason: classified.SystemReason,
364				Detail:       detail,
365			}, nil
366		case "":
367			return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: missing outcome")
368		default:
369			return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: unknown readiness outcome %q: expected one of actionable_atomic, actionable_but_rewritten, too_large_decomposed, operator_required, readiness_error, system_unready", out.Outcome)
370		}
371	}
372	
373	func decodeReadinessClassificationPayload(payload string) (PreClaimIntakeResult, error) {
374		var out preClaimReadinessClassificationPromptResult
375		if err := json.Unmarshal([]byte(payload), &out); err != nil {
376			return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: decode readiness classification result: %w", err)
377		}
378		reasons := failedReadinessReasons(out.ReadinessChecks)
379		detail := firstNonEmptyReadinessDetail(out.Rationale, out.Detail, out.Reasoning)
380		classified := ClassifyReadiness(out.Classification, reasons, detail)
381		if detail == "" {
382			detail = readinessCheckEvidence(out.ReadinessChecks)
383		}
384		detail = readinessDetailWithReason(classified, detail)
385	
386		rewrite := PreClaimIntakeRewrite{
387			Description:   strings.TrimSpace(out.Rewrite.Description),
388			Acceptance:    strings.TrimSpace(out.Rewrite.Acceptance),
389			ChangedFields: normalizePreClaimIntakeRewriteFields(out.Rewrite.ChangedFields),
390		}
391		result := PreClaimIntakeResult{
392			Outcome:      classified.IntakeOutcome,
393			Reason:       classified.Reason,
394			SystemReason: classified.SystemReason,
395			Detail:       detail,
396		}
397		if classified.Classification == ReadinessClassificationNeedsRefine && hasPreClaimIntakeRewrite(rewrite) {
398			result.Outcome = PreClaimIntakeActionableButRewritten
399			result.Rewrite = rewrite
400		}
401		return result, nil
402	}
403	
404	func failedReadinessReasons(checks []preClaimReadinessCheck) []string {
405		reasons := make([]string, 0, len(checks))
406		for _, check := range checks {
407			verdict := strings.ToLower(strings.TrimSpace(check.Verdict))
408			if verdict != "fail" {
409				continue
410			}
411			if reason := strings.TrimSpace(check.Reason); reason != "" {
412				reasons = append(reasons, reason)
413			}
414		}
415		return reasons
416	}
417	
418	func readinessCheckEvidence(checks []preClaimReadinessCheck) string {
419		for _, check := range checks {
420			if strings.ToLower(strings.TrimSpace(check.Verdict)) != "fail" {
421				continue
422			}
423			if evidence := strings.TrimSpace(check.Evidence); evidence != "" {
424				return evidence
425			}
426		}
427		return ""
428	}
429	
430	func readinessDetailWithReason(classified ReadinessClassificationResult, detail string) string {
431		detail = strings.TrimSpace(detail)
432		reason := strings.TrimSpace(classified.Reason)
433		if reason == "" {
434			return detail
435		}
436		if detail == "" {
437			return reason
438		}
439		if strings.Contains(strings.ToLower(detail), strings.ToLower(reason)) {
440			return detail
441		}
442		return reason + ": " + detail
443	}
444	
445	func firstNonEmptyReadinessDetail(values ...string) string {
446		for _, value := range values {
447			if trimmed := strings.TrimSpace(value); trimmed != "" {
448				return trimmed
449			}
450		}
451		return ""
452	}
453	
454	func hasPreClaimIntakeRewrite(rewrite PreClaimIntakeRewrite) bool {
455		return strings.TrimSpace(rewrite.Description) != "" ||
456			strings.TrimSpace(rewrite.Acceptance) != "" ||
457			len(rewrite.ChangedFields) > 0
458	}
459	
460	func decodeLegacyIntakePayload(payload string) (PreClaimIntakeResult, error) {
461		var out preClaimIntakePromptResult
462		if err := json.Unmarshal([]byte(payload), &out); err != nil {
463			return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: decode result: %w", err)
464		}
465		switch strings.ToLower(strings.TrimSpace(out.Classification)) {
466		case "atomic", "ok", "ready", "actionable", "pass":
467			return PreClaimIntakeResult{Outcome: PreClaimIntakeActionableAtomic, Detail: strings.TrimSpace(out.Reasoning)}, nil
468		case "rewritten":
469			return PreClaimIntakeResult{
470				Outcome: PreClaimIntakeActionableButRewritten,
471				Detail:  strings.TrimSpace(out.Reasoning),
472				Rewrite: PreClaimIntakeRewrite{
473					Description:   strings.TrimSpace(out.Rewrite.Description),
474					Acceptance:    strings.TrimSpace(out.Rewrite.Acceptance),
475					ChangedFields: normalizePreClaimIntakeRewriteFields(out.Rewrite.ChangedFields),
476				},
477			}, nil
478		case "decomposable":
479			return PreClaimIntakeResult{Outcome: PreClaimIntakeTooLargeDecomposed, Detail: strings.TrimSpace(out.Reasoning)}, nil
480		case "ambiguous", "ambiguous_scope", "needs_human", "ambiguous_needs_human":
481			return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: legacy classification %q removed by lifecycle migration; use outcome %q", out.Classification, PreClaimIntakeOperatorRequired)
482		case "":
483			return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: missing classification")
484		default:
485			return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: unknown classification %q", out.Classification)
486		}
487	}
