19	// LintHookErrorKind classifies infra failures returned by the pre-dispatch
20	// lint hook. The execute loop treats these as fail-open warnings rather than
21	// quality-policy results.
22	type LintHookErrorKind string
23	
24	const (
25		LintHookErrorKindMissingSkill    LintHookErrorKind = "missing-skill"
26		LintHookErrorKindMissingHarness  LintHookErrorKind = "missing-harness"
27		LintHookErrorKindEmptyOutput     LintHookErrorKind = "empty-output"
28		LintHookErrorKindBadJSON         LintHookErrorKind = "bad-json"
29		LintHookErrorKindCanceled        LintHookErrorKind = "canceled"
30		LintHookErrorKindDispatchFailure LintHookErrorKind = "dispatch-failure"
31	)
32	
33	// LintHookError is a typed infrastructure error returned by the lint hook.
34	// The Kind field is stable for errors.Is comparisons; Err carries the wrapped
35	// cause for logs and diagnostics.
36	type LintHookError struct {
37		Kind LintHookErrorKind
38		Err  error
39	}
40	
41	func (e *LintHookError) Error() string {
42		if e == nil {
43			return "<nil>"
44		}
45		if e.Err == nil {
46			return "lint hook: " + string(e.Kind)
47		}
48		return fmt.Sprintf("lint hook: %s: %v", e.Kind, e.Err)
49	}
50	
51	func (e *LintHookError) Unwrap() error {
52		if e == nil {
53			return nil
54		}
55		return e.Err
56	}
57	
58	func (e *LintHookError) Is(target error) bool {
59		t, ok := target.(*LintHookError)
60		if !ok || e == nil || t == nil {
61			return false
62		}
63		return e.Kind == t.Kind
64	}
65	
66	var (
67		ErrLintHookMissingSkill   = &LintHookError{Kind: LintHookErrorKindMissingSkill}
68		ErrLintHookMissingHarness = &LintHookError{Kind: LintHookErrorKindMissingHarness}
69		ErrLintHookEmptyOutput    = &LintHookError{Kind: LintHookErrorKindEmptyOutput}
70		ErrLintHookBadJSON        = &LintHookError{Kind: LintHookErrorKindBadJSON}
71		ErrLintHookCanceled       = &LintHookError{Kind: LintHookErrorKindCanceled}
72		ErrLintHookDispatch       = &LintHookError{Kind: LintHookErrorKindDispatchFailure}
73	)
