163	func buildPreDispatchLintPrompt(b *bead.Bead) (string, error) {
164		env := lintPromptBead{
165			ID:          b.ID,
166			Title:       strings.TrimSpace(b.Title),
167			Type:        b.IssueType,
168			Labels:      append([]string(nil), b.Labels...),
169			Parent:      strings.TrimSpace(b.Parent),
170			Deps:        append([]string(nil), b.DepIDs()...),
171			Description: strings.TrimSpace(b.Description),
172			Acceptance:  strings.TrimSpace(b.Acceptance),
173			Notes:       strings.TrimSpace(b.Notes),
174		}
175		if len(b.Extra) > 0 {
176			env.Custom = lintPromptCustomFields(b.Extra)
177		}
178	
179		body, err := json.MarshalIndent(env, "", "  ")
180		if err != nil {
181			return "", err
182		}
183	
184		var sb strings.Builder
185		sb.WriteString("MODE: lint\n")
186		sb.WriteString("You are the bead-lifecycle skill. Score the bead below using lint mode and return exactly one JSON object matching LintResult.\n")
187		sb.WriteString("Return only JSON with these top-level fields.\n")
188		sb.WriteString("Required output shape example: {\"score\":0,\"rationale\":\"\",\"suggested_fixes\":[],\"waivers_applied\":[]}\n")
189		sb.WriteString("Do not wrap the answer in markdown or prose.\n\n")
190		sb.WriteString("```json\n")
191		sb.Write(body)
192		sb.WriteString("\n```\n")
193		return sb.String(), nil
194	}
