196	func lintResultPayload(result *Result) (string, error) {
197		if result == nil {
198			return "", &LintHookError{Kind: LintHookErrorKindEmptyOutput, Err: fmt.Errorf("nil result")}
199		}
200		text := strings.TrimSpace(result.CondensedOutput)
201		if text == "" {
202			text = strings.TrimSpace(result.Output)
203		}
204		if text == "" {
205			if strings.TrimSpace(result.Error) != "" {
206				return "", &LintHookError{Kind: LintHookErrorKindDispatchFailure, Err: errors.New(strings.TrimSpace(result.Error))}
207			}
208			if result.ExitCode != 0 {
209				return "", &LintHookError{Kind: LintHookErrorKindDispatchFailure, Err: fmt.Errorf("exit code %d with empty output", result.ExitCode)}
210			}
211			return "", ErrLintHookEmptyOutput
212		}
213		candidate, ok := extractJSONCandidate(text)
214		if !ok {
215			return "", &LintHookError{Kind: LintHookErrorKindBadJSON, Err: fmt.Errorf("no JSON object found")}
216		}
217		return candidate, nil
218	}
219	
220	func lintPromptCustomFields(extra map[string]any) map[string]any {
221		if len(extra) == 0 {
222			return nil
223		}
224		out := make(map[string]any, len(extra))
225		for k, v := range extra {
226			key := strings.TrimSpace(k)
227			if key == "" || lintPromptSkipCustomField(key) {
228				continue
229			}
230			if val, ok := lintPromptSafeCustomValue(v); ok {
231				out[key] = val
232			}
233		}
234		if len(out) == 0 {
235			return nil
236		}
237		return out
238	}
239	
240	func lintPromptSkipCustomField(key string) bool {
241		switch key {
242		case "events", "events_attachment", "session_id", "closing_commit_sha":
243			return true
244		}
245		for _, prefix := range []string{"claimed-", "execute-loop-", "cancel-"} {
246			if strings.HasPrefix(key, prefix) {
247				return true
248			}
249		}
250		return false
251	}
252	
253	func lintPromptSafeCustomValue(v any) (any, bool) {
254		switch val := v.(type) {
255		case nil:
256			return nil, true
257		case string:
258			if len(val) > 4096 {
259				return nil, false
260			}
261			return val, true
262		case bool, int, int8, int16, int32, int64, uint, uint8, uint16, uint32, uint64, float32, float64:
263			return val, true
264		case []string:
265			if len(val) > 32 {
266				return nil, false
267			}
268			cp := make([]string, 0, len(val))
269			for _, item := range val {
270				if len(item) > 512 {
271					return nil, false
272				}
273				cp = append(cp, item)
274			}
275			return cp, true
276		case []any:
277			if len(val) > 32 {
278				return nil, false
279			}
280			cp := make([]string, 0, len(val))
281			for _, item := range val {
282				s, ok := item.(string)
283				if !ok || len(s) > 512 {
284					return nil, false
285				}
286				cp = append(cp, s)
287			}
288			return cp, true
289		default:
290			return nil, false
291		}
292	}
