338	func beadLifecycleSkillMissingError(diag BeadLifecycleSkillDiagnostics, cause error) error {
339		parts := []string{"skill missing: bead-lifecycle"}
340		if diag.ProjectRoot != "" {
341			parts = append(parts, "project_root="+diag.ProjectRoot)
342		}
343		if len(diag.CheckedPaths) > 0 {
