package agent

import (
	"context"
	"encoding/json"
	"fmt"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/DocumentDrivenDX/ddx/internal/bead/accheck"
)

// DefaultACQualityMinScore is the default fraction of AC items that must be
// mechanically classifiable (non-prose) for the pre-claim quality gate to pass.
const DefaultACQualityMinScore = 0.5

// ACQualityItem holds the classification of one parsed AC line.
type ACQualityItem struct {
	AC         int    `json:"ac"`
	Text       string `json:"text"`
	Kind       string `json:"kind"`
	Verifiable bool   `json:"verifiable"`
}

// ACQualityResult is the verifiability assessment of a bead's acceptance text.
// Score = VerifiableCount / Total; PassesThreshold = Score >= Threshold.
type ACQualityResult struct {
	Score           float64         `json:"score"`
	VerifiableCount int             `json:"verifiable_count"`
	ProseCount      int             `json:"prose_count"`
	Total           int             `json:"total"`
	Items           []ACQualityItem `json:"items"`
	PassesThreshold bool            `json:"passes_threshold"`
	Threshold       float64         `json:"threshold"`
}

// BeadACQualityStore is the minimal store interface required by the AC quality gate.
type BeadACQualityStore interface {
	Get(id string) (*bead.Bead, error)
	Update(id string, mutate func(*bead.Bead)) error
	AppendEvent(id string, event bead.BeadEvent) error
}

// CheckACQuality parses acceptance text and computes a verifiability score.
// verifiable_count = items classified as test-name | symbol | negative |
// build-gate | mechanical. score = verifiable_count / total; 0 when total == 0.
func CheckACQuality(acceptance string, threshold float64) ACQualityResult {
	items := accheck.ParseAcceptance(acceptance)
	total := len(items)
	result := ACQualityResult{
		Threshold: threshold,
		Total:     total,
		Items:     make([]ACQualityItem, 0, total),
	}
	if total == 0 {
		return result
	}
	for _, item := range items {
		verifiable := item.Kind != accheck.KindProse
		result.Items = append(result.Items, ACQualityItem{
			AC:         item.AC,
			Text:       item.Text,
			Kind:       string(item.Kind),
			Verifiable: verifiable,
		})
		if verifiable {
			result.VerifiableCount++
		} else {
			result.ProseCount++
		}
	}
	result.Score = float64(result.VerifiableCount) / float64(total)
	result.PassesThreshold = result.Score >= threshold
	return result
}

// MarkBeadACQualityLow sets execution-eligible=false, adds the label
// "ac-quality:needs-refinement", and emits an "ac-quality-low" event with
// per-AC classifications in the body. Safe to call more than once (idempotent
// label add; events are append-only).
func MarkBeadACQualityLow(store BeadACQualityStore, beadID string, result ACQualityResult) error {
	if err := store.Update(beadID, func(b *bead.Bead) {
		if b.Extra == nil {
			b.Extra = make(map[string]any)
		}
		b.Extra["execution-eligible"] = false
		if !beadHasACQualityLabel(b.Labels) {
			b.Labels = append(b.Labels, "ac-quality:needs-refinement")
		}
	}); err != nil {
		return fmt.Errorf("ac-quality: update bead: %w", err)
	}
	body, _ := json.Marshal(result.Items)
	return store.AppendEvent(beadID, bead.BeadEvent{
		Kind: "ac-quality-low",
		Summary: fmt.Sprintf("score=%.2f threshold=%.2f verifiable=%d/%d",
			result.Score, result.Threshold, result.VerifiableCount, result.Total),
		Body:   string(body),
		Source: "preclaim-ac-quality",
	})
}

func beadHasACQualityLabel(labels []string) bool {
	for _, l := range labels {
		if l == "ac-quality:needs-refinement" {
			return true
		}
	}
	return false
}

// NewACQualityPreClaimGate returns a PreClaimIntakeHook that checks the bead's
// AC verifiability score before any execution attempt. When score < threshold,
// the bead is marked ineligible (execution-eligible=false, label added, event
// emitted) and PreClaimIntakeOperatorRequired is returned to block claim. When
// score >= threshold, inner is called (if non-nil) or
// PreClaimIntakeActionableAtomic is returned.
//
// This gate is deterministic: no LLM call is made. It should be chained
// before the LLM-based intake hook so that beads with low-quality ACs never
// burn drain budget.
func NewACQualityPreClaimGate(store BeadACQualityStore, threshold float64, inner PreClaimIntakeHook) PreClaimIntakeHook {
	return func(ctx context.Context, beadID string) (PreClaimIntakeResult, error) {
		if ctx != nil {
			if err := ctx.Err(); err != nil {
				return PreClaimIntakeResult{}, err
			}
		}
		b, err := store.Get(beadID)
		if err != nil {
			// Fail-open: delegate to inner hook on store read failure.
			if inner != nil {
				return inner(ctx, beadID)
			}
			return PreClaimIntakeResult{Outcome: PreClaimIntakeActionableAtomic}, nil
		}
		result := CheckACQuality(b.Acceptance, threshold)
		if !result.PassesThreshold {
			_ = MarkBeadACQualityLow(store, beadID, result)
			return PreClaimIntakeResult{
				Outcome: PreClaimIntakeOperatorRequired,
				Reason:  "ac-quality:needs-refinement",
				Detail: fmt.Sprintf(
					"score %.2f below threshold %.2f (%d/%d verifiable ACs)",
					result.Score, threshold, result.VerifiableCount, result.Total),
			}, nil
		}
		if inner != nil {
			return inner(ctx, beadID)
		}
		return PreClaimIntakeResult{Outcome: PreClaimIntakeActionableAtomic}, nil
	}
}

package agent

import (
	"encoding/json"
	"fmt"
	"testing"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

func TestPreClaimACQuality_AllMechanicalACs_Passes(t *testing.T) {
	acceptance := "1. `ParseAcceptance` function exists in accheck\n2. TestFooBar passes\n3. cd cli && go test ./internal/agent/... green\n"
	result := CheckACQuality(acceptance, DefaultACQualityMinScore)
	assert.True(t, result.PassesThreshold)
	assert.Equal(t, 3, result.Total)
	assert.Equal(t, 3, result.VerifiableCount)
	assert.Equal(t, 0, result.ProseCount)
	for _, item := range result.Items {
		assert.True(t, item.Verifiable, "AC #%d should be verifiable but kind=%s: %s", item.AC, item.Kind, item.Text)
	}
}

func TestPreClaimACQuality_AllProseACs_BlocksClaim(t *testing.T) {
	acceptance := "1. Improve logging clarity\n2. Make error messages cleaner\n3. Code is more readable\n"
	result := CheckACQuality(acceptance, DefaultACQualityMinScore)
	assert.False(t, result.PassesThreshold)
	assert.Equal(t, 3, result.Total)
	assert.Equal(t, 0, result.VerifiableCount)
	assert.Equal(t, 3, result.ProseCount)
	for _, item := range result.Items {
		assert.Equal(t, "prose", item.Kind, "AC #%d should be prose: %s", item.AC, item.Text)
		assert.False(t, item.Verifiable)
	}
}

func TestPreClaimACQuality_MixedACs_ScoreAboveThreshold_Passes(t *testing.T) {
	// 2 verifiable (test-name, symbol), 1 prose => score = 2/3 ≈ 0.667 >= 0.5
	acceptance := "1. TestFooBar passes\n2. `NewStore` function added\n3. improve clarity\n"
	result := CheckACQuality(acceptance, DefaultACQualityMinScore)
	assert.True(t, result.PassesThreshold)
	assert.Equal(t, 3, result.Total)
	assert.Equal(t, 2, result.VerifiableCount)
	assert.Equal(t, 1, result.ProseCount)
	assert.InDelta(t, 2.0/3.0, result.Score, 0.01)
}

func TestPreClaimACQuality_MixedACs_ScoreBelowThreshold_Routes(t *testing.T) {
	// 1 verifiable (test-name), 3 prose => score = 1/4 = 0.25 < 0.5
	acceptance := "1. TestFooBar passes\n2. improve clarity\n3. better error messages\n4. more readable code\n"
	result := CheckACQuality(acceptance, DefaultACQualityMinScore)
	assert.False(t, result.PassesThreshold)
	assert.Equal(t, 4, result.Total)
	assert.Equal(t, 1, result.VerifiableCount)
	assert.Equal(t, 3, result.ProseCount)
	assert.InDelta(t, 0.25, result.Score, 0.01)
}

func TestPreClaimACQuality_LowQualityEmitsACQualityEvent(t *testing.T) {
	b := &bead.Bead{
		ID:         "ddx-test0001",
		Title:      "Test bead",
		Acceptance: "1. Improve clarity\n2. Better error messages\n",
	}
	store := &acQualityTestStore{b: b}

	result := CheckACQuality(b.Acceptance, DefaultACQualityMinScore)
	require.False(t, result.PassesThreshold, "expected all-prose ACs to fail threshold")

	err := MarkBeadACQualityLow(store, b.ID, result)
	require.NoError(t, err)

	require.Len(t, store.events, 1, "expected exactly one ac-quality-low event")
	ev := store.events[0]
	assert.Equal(t, "ac-quality-low", ev.Kind)
	assert.Contains(t, ev.Summary, "score=0.00")
	assert.Contains(t, ev.Summary, fmt.Sprintf("threshold=%.2f", DefaultACQualityMinScore))

	var items []ACQualityItem
	require.NoError(t, json.Unmarshal([]byte(ev.Body), &items))
	assert.Len(t, items, 2)

	// Bead must be marked ineligible and labeled.
	assert.Equal(t, false, store.b.Extra["execution-eligible"])
	assert.True(t, beadHasACQualityLabel(store.b.Labels))
}

// acQualityTestStore is a minimal in-memory store for AC quality tests.
type acQualityTestStore struct {
	b      *bead.Bead
	events []bead.BeadEvent
}

func (s *acQualityTestStore) Get(id string) (*bead.Bead, error) {
	if s.b == nil || s.b.ID != id {
		return nil, fmt.Errorf("bead %s not found", id)
	}
	cp := *s.b
	return &cp, nil
}

func (s *acQualityTestStore) Update(id string, mutate func(*bead.Bead)) error {
	if s.b == nil || s.b.ID != id {
		return fmt.Errorf("bead %s not found", id)
	}
	b := *s.b
	mutate(&b)
	s.b = &b
	return nil
}

func (s *acQualityTestStore) AppendEvent(id string, event bead.BeadEvent) error {
	s.events = append(s.events, event)
	return nil
}

package cmd

import (
	"encoding/json"
	"fmt"
	"io"

	"github.com/DocumentDrivenDX/ddx/internal/agent"
	"github.com/DocumentDrivenDX/ddx/internal/config"
	"github.com/spf13/cobra"
)

// newBeadLintCommand wires `ddx bead lint <id>` — ad-hoc AC verifiability
// check. It classifies each AC into a kind (test-name | build-gate | negative
// | symbol | mechanical | prose), computes a verifiability score, and reports
// whether the bead meets the configured threshold. No LLM calls are made; the
// check is purely deterministic. Operators use this to self-check a bead
// before filing or dispatching it.
func (f *CommandFactory) newBeadLintCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "lint <bead-id>",
		Short: "Check acceptance criteria mechanical verifiability",
		Long: `lint classifies each AC into a kind (test-name | build-gate |
negative | symbol | mechanical | prose) and computes a verifiability
score (verifiable_count / total). The score is compared to the
configured threshold (default 0.5; override via intake.ac_quality.min_score
in .ddx/config.yaml).

No LLM calls are made. Use this command to self-check a bead before
filing or dispatching it.

Examples:
  ddx bead lint ddx-abc123
  ddx bead lint ddx-abc123 --json`,
		Args: cobra.ExactArgs(1),
		RunE: func(cmd *cobra.Command, args []string) error {
			beadID := args[0]
			s := f.beadStore()
			b, err := s.Get(beadID)
			if err != nil {
				return fmt.Errorf("bead %s: %w", beadID, err)
			}
			if b == nil {
				return fmt.Errorf("bead %s not found", beadID)
			}

			threshold := agent.DefaultACQualityMinScore
			workspaceRoot := f.beadWorkspaceRoot()
			if workspaceRoot == "" {
				workspaceRoot = f.WorkingDir
			}
			if cfg, cfgErr := config.LoadWithWorkingDir(workspaceRoot); cfgErr == nil {
				threshold = cfg.ResolveACQualityMinScore()
			}

			result := agent.CheckACQuality(b.Acceptance, threshold)

			asJSON, _ := cmd.Flags().GetBool("json")
			if asJSON {
				blob, mErr := json.MarshalIndent(result, "", "  ")
				if mErr != nil {
					return mErr
				}
				fmt.Fprintln(cmd.OutOrStdout(), string(blob))
				return nil
			}
			return writeBeadLintHuman(cmd.OutOrStdout(), beadID, result)
		},
	}
	cmd.Flags().Bool("json", false, "emit JSON to stdout instead of the human-readable table")
	return cmd
}

func writeBeadLintHuman(w io.Writer, beadID string, r agent.ACQualityResult) error {
	fmt.Fprintf(w, "bead lint for %s\n", beadID)
	verdict := "FAILS"
	if r.PassesThreshold {
		verdict = "PASSES"
	}
	fmt.Fprintf(w, "score: %.2f (%d/%d verifiable)  %s threshold %.2f\n\n",
		r.Score, r.VerifiableCount, r.Total, verdict, r.Threshold)
	for _, item := range r.Items {
		verifiableLabel := "prose"
		if item.Verifiable {
			verifiableLabel = "verifiable"
		}
		fmt.Fprintf(w, "AC #%d  [%-13s]  %-10s  %s\n",
			item.AC, item.Kind, verifiableLabel, truncateLintText(item.Text, 80))
	}
	return nil
}

func truncateLintText(s string, n int) string {
	if len(s) <= n {
		return s
	}
	return s[:n-1] + "…"
}

